codeExamples.code:
let c = 1234;
c = null;
console.log(c);
console.log(typeof null);

let a = "5";
a = parseInt(a);
console.log(a + 3);

let b = 1;
b = b.toString();
console.log(b + 1);

// undefined 常見情境：存取不存在的屬性
let user = { name: "Wayne" };
console.log(user.age);

// undefined 常見情境：函式沒有 return
function sayHi() {
  let msg = "Hi";
}
console.log(sayHi());

// null 常見情境：登出時主動清空使用者資料
let user = { name: "Wayne" };
console.log(user);
user = null; // 登出，清空資料
console.log(user);

// falsy 值：會被當成 false
if (0) {
  console.log("不會印出");
}
if ("") {
  console.log("不會印出");
}
if (null) {
  console.log("不會印出");
}
console.log("以上三個 if 都不會執行");

// truthy 值：會被當成 true
if ("hello") {
  console.log("字串有內容是 truthy");
}
if (1) {
  console.log("非零數字是 truthy");
}
if ([]) {
  console.log("空陣列也是 truthy！");
}

